export default function CropAdvisor(){

const crops=[

'Rice',

'Cotton',

'Tomato',

'Maize'

];

return(

<div style={{padding:'20px'}}>

<h2>Crop Advisor</h2>

{crops.map(crop=>

<p key={crop}>{crop}</p>

)}

</div>

)

}
